#!/usr/bin/env python3
"""Dashboard generator v4 — product images embedded as data: URIs."""
import json, pathlib
from datetime import datetime

# Pre-embedded base64 JPEG images extracted from retailer sites at 300px canvas
_TEC  = ""
_MULE = ""
_POLO = ""
_CARD = ""

IMG_B64 = {1: _TEC, 2: _MULE, 3: _POLO, 4: _CARD}

def load_state():
    p = pathlib.Path(__file__).parent / "tracker_state.json"
    return json.loads(p.read_text())

def get_latest(ph, pid):
    entries = sorted([e for e in ph if e["product_id"]==pid], key=lambda x:x["scraped_at"], reverse=True)
    return entries[0] if entries else None

def price_change_pct(ph, pid):
    entries = sorted([e for e in ph if e["product_id"]==pid and e.get("price")], key=lambda x:x["scraped_at"])
    if len(entries) < 2: return None
    return ((entries[-1]["price"] - entries[0]["price"]) / entries[0]["price"]) * 100

def fmt(p): return "—" if p is None else f"${p:.2f}"

def build_card(product, latest, change_pct, b64):
    pid, title, url = product["id"], product["title"], product["url"]
    price    = latest["price"] if latest else None
    in_stock = latest.get("in_stock", False) if latest else False
    scraped  = latest["scraped_at"][:10] if latest else "—"
    if b64:
        img_src = f"data:image/jpeg;base64,{b64}"
    else:
        img_src = product.get("image_url") or (latest.get("image_url") if latest else None)
    img_html = (f'<img src="{img_src}" alt="{title}" class="product-img">'
                if img_src else '<div class="img-placeholder">No Image</div>')
    stock_badge = ('<span class="badge badge-out">Out of Stock</span>'
                   if not in_stock else '<span class="badge badge-in">In Stock</span>')
    chg_html = ""
    if change_pct is not None:
        arrow = "▼" if change_pct <= 0 else "▲"
        cls = "change-down" if change_pct <= 0 else "change-up"
        chg_html = f'<span class="{cls}">{arrow} {abs(change_pct):.1f}%</span>'
    variant = product.get("variant", {})
    vbits = []
    if "size"  in variant: vbits.append(f'Size: {variant["size"]}')
    if "color" in variant: vbits.append(f'Color: {variant["color"].replace("-"," ").title()}')
    vhtml = f'<p class="variant">{" · ".join(vbits)}</p>' if vbits else ""
    title_esc = title.replace("'", "\\'")
    return f"""
    <div class="card" id="card-{pid}">
      <button class="unfollow-btn" onclick="unfollowProduct({pid}, '{title_esc}')" title="Stop tracking">✕</button>
      <a href="{url}" target="_blank" class="img-link">
        <div class="img-wrap">{img_html}</div>
      </a>
      <div class="card-body">
        <a href="{url}" target="_blank" class="product-title">{title}</a>
        {vhtml}
        <div class="price-row">
          <span class="price">{fmt(price)}</span>
          {stock_badge}
        </div>
        <div class="meta-row">
          {chg_html}
          <span class="last-checked">Updated {scraped}</span>
        </div>
        <a href="{url}" target="_blank" class="shop-btn">View Product →</a>
      </div>
    </div>"""

CSS = """
  *,*::before,*::after{box-sizing:border-box;margin:0;padding:0}
  body{font-family:-apple-system,BlinkMacSystemFont,'Segoe UI',Roboto,sans-serif;background:#f5f5f5;color:#111;min-height:100vh}
  header{background:#fff;border-bottom:1px solid #e5e5e5;padding:20px 32px;display:flex;align-items:center;justify-content:space-between;position:sticky;top:0;z-index:10;box-shadow:0 1px 3px rgba(0,0,0,.06)}
  .logo{font-size:18px;font-weight:700;letter-spacing:-.3px;color:#111}
  .logo span{color:#2563eb}
  .header-meta{font-size:12px;color:#888}
  .grid{display:grid;grid-template-columns:repeat(auto-fill,minmax(270px,1fr));gap:24px;max-width:1200px;margin:36px auto;padding:0 24px}
  .card{background:#fff;border-radius:12px;overflow:hidden;box-shadow:0 1px 4px rgba(0,0,0,.08),0 4px 16px rgba(0,0,0,.04);transition:transform .15s ease,box-shadow .15s ease;display:flex;flex-direction:column;position:relative}
  .card:hover{transform:translateY(-2px);box-shadow:0 4px 12px rgba(0,0,0,.12),0 8px 24px rgba(0,0,0,.06)}
  .unfollow-btn{position:absolute;top:8px;right:8px;width:26px;height:26px;border-radius:50%;border:none;background:rgba(0,0,0,.45);color:#fff;font-size:13px;line-height:1;cursor:pointer;display:flex;align-items:center;justify-content:center;opacity:0;transition:opacity .15s,background .15s;z-index:5;backdrop-filter:blur(2px)}
  .card:hover .unfollow-btn{opacity:1}
  .unfollow-btn:hover{background:#ef4444!important;opacity:1}
  .img-link{display:block;text-decoration:none}
  .img-wrap{width:100%;aspect-ratio:4/5;overflow:hidden;background:#fafafa}
  .product-img{width:100%;height:100%;object-fit:cover;object-position:center top;display:block;transition:transform .3s ease}
  .card:hover .product-img{transform:scale(1.04)}
  .img-placeholder{width:100%;height:100%;display:flex;align-items:center;justify-content:center;color:#bbb;font-size:14px;background:#f0f0f0}
  .card-body{padding:16px 18px 20px;display:flex;flex-direction:column;gap:8px;flex:1}
  .product-title{font-size:14px;font-weight:600;color:#111;line-height:1.35;text-decoration:none;display:-webkit-box;-webkit-line-clamp:2;-webkit-box-orient:vertical;overflow:hidden}
  .product-title:hover{color:#2563eb}
  .variant{font-size:12px;color:#666;text-transform:capitalize}
  .price-row{display:flex;align-items:center;gap:10px;margin-top:4px}
  .price{font-size:22px;font-weight:700;color:#111;letter-spacing:-.5px}
  .badge{font-size:10px;font-weight:600;padding:3px 8px;border-radius:20px;text-transform:uppercase;letter-spacing:.5px}
  .badge-in{background:#dcfce7;color:#15803d}
  .badge-out{background:#fee2e2;color:#b91c1c}
  .meta-row{display:flex;align-items:center;justify-content:space-between;font-size:11px}
  .change-down{color:#16a34a;font-weight:600}
  .change-up{color:#dc2626;font-weight:600}
  .last-checked{color:#aaa}
  .shop-btn{display:inline-block;margin-top:8px;padding:9px 16px;background:#111;color:#fff;border-radius:8px;font-size:13px;font-weight:600;text-decoration:none;text-align:center;transition:background .15s}
  .shop-btn:hover{background:#2563eb}
  footer{text-align:center;padding:24px;font-size:12px;color:#bbb}
"""

def main():
    state = load_state()
    ph = state["price_history"]
    cards = [build_card(p, get_latest(ph, p["id"]), price_change_pct(ph, p["id"]), IMG_B64.get(p["id"]))
             for p in state["products"] if p.get("active", True)]
    ts = datetime.utcnow().strftime("%Y-%m-%d %H:%M UTC")
    n = len(cards)
    html = f"""<!DOCTYPE html>
<html lang="en">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width,initial-scale=1.0">
<title>Price Tracker Dashboard</title>
<style>{CSS}</style>
</head>
<body>
<header>
  <div class="logo">Price<span>Tracker</span></div>
  <div class="header-meta">Generated {ts} · {n} products tracked</div>
</header>
<main><div class="grid">{"".join(cards)}</div></main>
<footer>Prices sourced from retailer websites. Check links for current availability.</footer>
<script>
function unfollowProduct(id, title) {{
  if (!confirm('Stop tracking "' + title + '"?\\nThis will remove it from price monitoring.')) return;
  var card = document.getElementById('card-' + id);
  if (card) {{
    card.style.transition = 'opacity .25s, transform .25s';
    card.style.opacity = '0';
    card.style.transform = 'scale(0.95)';
    setTimeout(function() {{ card.style.display = 'none'; }}, 280);
  }}
  if (typeof sendPrompt === 'function') {{
    sendPrompt('Unfollow product ID: ' + id + ' (' + title + ')');
  }}
}}
</script>
</body>
</html>"""
    base = pathlib.Path(__file__).parent
    out = base / "dashboard.html"
    out.write_text(html, encoding="utf-8")
    # Also write index.html so GitHub Pages serves it at the repo root URL
    (base / "index.html").write_text(html, encoding="utf-8")
    print(f"Written {out} ({len(html)//1024}KB)")

if __name__ == "__main__":
    main()
